import React, { useEffect, useMemo, useState } from "react";
import "./PathologyPage.css";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:5000/api";

const PathologyPage = () => {
  const [selected, setSelected] = useState(null);
  const [search, setSearch] = useState("");
  const [showSuggestions, setShowSuggestions] = useState(false);

  // keep your original static sections
  const healthCheckups = [
    { id: "hc-std", title: "STD Checkups", img: "https://cdn-icons-png.flaticon.com/512/4140/4140048.png", oldPrice: 2990, price: 1499, discount: "50% Off", tests: ["HBsAg (ECLIA)", "VDRL Qualitative", "Hepatitis C Virus antibodies (Anti HCV)", "HIV 1 & 2 (screening)"], reportTime: "12 hours", description: "Essential sexually-transmitted infections panel." },
    { id: "hc-fever", title: "Fever Checkups", img: "https://cdn-icons-png.flaticon.com/512/2704/2704608.png", oldPrice: 1200, price: 699, discount: "42% Off", tests: ["CBC", "CRP", "Malaria (if indicated)", "Urine Routine"], reportTime: "8 hours", description: "Quick fever panel to identify infection markers." },
    { id: "hc-pcod", title: "PCOD Checkups", img: "https://cdn-icons-png.flaticon.com/512/3004/3004613.png", oldPrice: 2100, price: 1199, discount: "43% Off", tests: ["Hormone profile (LH/FSH)", "Prolactin", "TSH"], reportTime: "24 hours", description: "Hormone panel commonly used for PCOD screening." },
    { id: "hc-senior", title: "Senior Citizen Checkups", img: "https://thumbs.dreamstime.com/b/elderly-patient-medical-care-hospital-vector-illustration-doctor-character-take-old-senior-man-blood-pressure-elderly-181606148.jpg", oldPrice: 5999, price: 2999, discount: "50% Off", tests: ["CBC", "LFT", "KFT", "Lipid Profile", "Blood Sugar", "Thyroid"], reportTime: "24–36 hours", description: "Comprehensive package for elderly health monitoring." },
  ];

  // 🔹 NEW: fetch tests from backend (admin-managed)
  const [testsFromApi, setTestsFromApi] = useState([]);
  useEffect(() => {
    (async () => {
      try {
        const res = await fetch(`${API_BASE}/public/tests`);
        const data = await res.json();
        // normalize to your card structure
        const mapped = (Array.isArray(data) ? data : []).map((t) => ({
          id: t._id,
          title: t.name || t.title || "Lab Test",
          img: "https://cdn-icons-png.flaticon.com/512/684/684908.png",
          oldPrice: t.oldPrice || undefined,
          price: t.price || undefined,
          discount: t.discount ? `${t.discount}% Off` : undefined,
          tests: [],
          reportTime: t.reportTime || "24 hours",
          description: t.description || "Diagnostic test",
        }));
        setTestsFromApi(mapped);
      } catch (_) {
        setTestsFromApi([]);
      }
    })();
  }, []);

  const fullBodyCheckups = [
    { id: "fb-basic", title: "Full Body Checkup - Essential", img: "https://cdn-icons-png.flaticon.com/512/2645/2645874.png", oldPrice: 5399, price: 1599, discount: "70% Off", tests: ["CBC","Blood Sugar (Fasting)","Lipid Profile","Liver Function Test","Kidney Function Test","TSH (Thyroid)"], reportTime: "24 hours", description: "Core full-body essential package for routine screening." },
    { id: "fb-advanced", title: "Full Body Checkup - Advanced", img: "https://cdn-icons-png.flaticon.com/512/2645/2645874.png", oldPrice: 8499, price: 2699, discount: "68% Off", tests: ["CBC","Complete Metabolic Panel","Lipid Profile","Thyroid Profile","Vitamin D","HbA1c"], reportTime: "24–36 hours", description: "Bigger panel covering metabolic and endocrine markers." },
    { id: "fb-ultra-male", title: "Ultra Full Body Checkup - Male", img: "https://cdn-icons-png.flaticon.com/512/3048/3048122.png", oldPrice: 34999, price: 11999, discount: "66% Off", tests: ["Complete blood panels","Advanced cardiac markers","Hormone profile","Vitamin D & B12","PSA"], reportTime: "48 hours", description: "Extensive package for in-depth male health screening." },
  ];

  const allItems = useMemo(
    () => [...healthCheckups, ...testsFromApi, ...fullBodyCheckups],
    [testsFromApi]
  );

  const openDetails = (item) => setSelected(item);
  const closeDetails = () => setSelected(null);

  const filteredItems = allItems.filter((item) =>
    item.title.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="pathology-page-root">
      <h1 className="page-title">Pathology — Checkups & Tests</h1>

      {/* Search Bar */}
      <div className="search-bar">
        <div className="search-wrapper">
          <input
            type="text"
            placeholder="Search for any test or package..."
            value={search}
            onChange={(e) => {
              setSearch(e.target.value);
              setShowSuggestions(true);
            }}
            onFocus={() => setShowSuggestions(true)}
            onBlur={() => setTimeout(() => setShowSuggestions(false), 150)}
          />
          <button className="search-btn">Search</button>

          {/* Suggestion Dropdown */}
          {showSuggestions && search && filteredItems.length > 0 && (
            <div className="suggestion-box">
              {filteredItems.map((item) => (
                <div
                  key={item.id}
                  className="suggestion-item"
                  onClick={() => {
                    openDetails(item);
                    setShowSuggestions(false);
                    setSearch("");
                  }}
                >
                  <strong>{item.title}</strong>
                  <span className="suggestion-sub">
                    ({(item.description || "Details").split(" ")[0]}…)
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Show filtered or all */}
      {search ? (
        <div className="cards-row">
          {filteredItems.length ? (
            filteredItems.map((item) => (
              <div key={item.id} className="card" onClick={() => openDetails(item)}>
                <img src={item.img} alt={item.title} className="card-img" />
                <div className="card-title">{item.title}</div>
                <div className="card-sub">
                  {item.price && <span className="card-price">₹{item.price}</span>}
                  {item.oldPrice && <span className="card-old">₹{item.oldPrice}</span>}
                  {item.discount && <span className="card-discount">{item.discount}</span>}
                </div>
              </div>
            ))
          ) : (
            <p className="no-results">No results found.</p>
          )}
        </div>
      ) : (
        <>
          {/* Popular Health Checkups */}
          <section className="section">
            <h2 className="section-heading">Popular Health Checkups</h2>
            <div className="cards-row">
              {healthCheckups.map((c) => (
                <div key={c.id} className="card" onClick={() => openDetails(c)}>
                  <img src={c.img} alt={c.title} className="card-img" />
                  <div className="card-title">{c.title}</div>
                  <div className="card-sub">
                    <span className="card-price">₹{c.price}</span>
                    <span className="card-old">₹{c.oldPrice}</span>
                  </div>
                </div>
              ))}
            </div>
          </section>

          {/* Popular Health Tests — now shows admin tests */}
          <section className="section">
            <h2 className="section-heading">Popular Health Tests</h2>
            <div className="cards-row">
              {testsFromApi.length ? (
                testsFromApi.map((c) => (
                  <div key={c.id} className="card" onClick={() => openDetails(c)}>
                    <img src={c.img} alt={c.title} className="card-img" />
                    <div className="card-title">{c.title}</div>
                    <div className="card-sub">
                      {c.price && <span className="card-price">₹{c.price}</span>}
                      {c.oldPrice && <span className="card-old">₹{c.oldPrice}</span>}
                    </div>
                  </div>
                ))
              ) : (
                <p className="no-results">No tests yet.</p>
              )}
            </div>
          </section>

          {/* Full Body Checkups */}
          <section className="section">
            <h2 className="section-heading">Full Body Checkups</h2>
            <div className="cards-row">
              {fullBodyCheckups.map((c) => (
                <div key={c.id} className="full-card" onClick={() => openDetails(c)}>
                  <img src={c.img} alt={c.title} className="card-img" />
                  <div className="full-title">{c.title}</div>
                  <div className="card-sub">
                    <span className="card-price">₹{c.price}</span>
                    <span className="card-old">₹{c.oldPrice}</span>
                    <span className="card-discount">{c.discount}</span>
                  </div>
                </div>
              ))}
            </div>
          </section>
        </>
      )}

      {/* Modal */}
      {selected && (
        <div className="modal-overlay" onClick={closeDetails}>
          <div className="modal-card" onClick={(e) => e.stopPropagation()}>
            <button className="modal-close" onClick={closeDetails}>×</button>
            <div className="modal-top">
              <img src={selected.img} alt={selected.title} className="modal-img" />
              <div className="modal-title-wrap">
                <div className="modal-title">{selected.title}</div>
                {selected.discount && <div className="modal-discount">{selected.discount}</div>}
                <div className="modal-price">
                  {selected.oldPrice && <span className="modal-old">₹{selected.oldPrice}</span>}
                  {selected.price && <span className="modal-new">₹{selected.price}</span>}
                </div>
              </div>
            </div>

            <div className="modal-body">
              <p className="modal-desc">{selected.description}</p>
              {selected.tests?.length ? (
                <div className="modal-section">
                  <div className="modal-subhead">Tests included</div>
                  <ul className="modal-tests">
                    {selected.tests.map((t, i) => (<li key={i}>{t}</li>))}
                  </ul>
                </div>
              ) : null}

              <div className="modal-meta">
                <span>Reports: <b>{selected.reportTime}</b></span>
                {selected.tests?.length ? (
                  <span className="modal-params">
                    {selected.tests.length} tests
                  </span>
                ) : null}
              </div>

              <div className="modal-actions">
                <button className="btn-add">+ Add</button>
                <button className="btn-details">View Details</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PathologyPage;
